  ('dietitian-moex-07074', 'dietitian', 'dietitian-moex-103-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '以魚為主食的愛斯基摩人，雖然攝取高脂飲食但是少有心臟病的問題，目前認為其可能原因是： 所攝取之冰原魚類富含長鏈的飽和脂肪酸，且膽固醇含量較低 這些魚類富含大量的奇數碳脂肪酸，在體內產生特殊代謝產物所致 大量的魚油攝取使得體內的凝血作用受到抑制 魚類提供大量膠原蛋白可以抑制體內發炎反應與膽固醇合成', '["", "", "", ""]'::jsonb, 2, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "387d240e6a2b", "answer_pdf_sha1": "3812a09b1c9a", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 27, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
