  ('dietitian-moex-07078', 'dietitian', 'dietitian-moex-103-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '構成蛋白質三級構造之交互作用不包括下列何者？ 肽鍵  疏水性交互作用  親水性交互作用  鹽橋', '["", "", "", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:45+00:00", "source_pdf_sha1": "387d240e6a2b", "answer_pdf_sha1": "3812a09b1c9a", "source_family": "moex-gov-tw", "moex": {"exam_code": "103100", "c": "106", "s": "0301", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "生理學與生物化學", "year": "103", "exam_name": "103年第二次專技醫師中醫師分階段、中醫師營養師心理師護理師社會工作師、法醫師語言聽力牙體技術師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
